import axios from '@nextcloud/axios';
import { generateOcsUrl } from '@nextcloud/router';
/**
 *
 */
export async function generateToken() {
  const {
    data
  } = await axios.get(generateOcsUrl('/apps/files_sharing/api/v1/token'));
  return data.ocs.data.token;
}